def test_create_procedure_missing_encounter_returns_422(
    base_url, clinician_auth_token
):
    payload = {
        "resourceType": "Procedure",
        "status": "completed",
        "code": {
            "coding": [{"system": "http://snomed.info/sct", "code": "80146002"}]
        },
        "subject": {"reference": "Patient/test-patient-1"}
        # encounter intentionally omitted
    }
    resp = requests.post(
        f"{base_url}/Procedure",
        json=payload,
        headers={"Authorization": f"Bearer {clinician_auth_token}"}
    )
    assert resp.status_code == 422, resp.text
    body = resp.json()
    error_text = str(body).lower()
    assert "encounter" in error_text

