def test_create_procedure_closed_encounter_returns_conflict(
    base_url, clinician_auth_token, closed_encounter_id
):
    payload = {
        "resourceType": "Procedure",
        "status": "completed",
        "code": {
            "coding": [{"system": "http://snomed.info/sct", "code": "80146002"}]
        },
        "subject": {"reference": "Patient/test-patient-1"},
        "encounter": {"reference": f"Encounter/{closed_encounter_id}"}
    }
    resp = requests.post(
        f"{base_url}/Procedure",
        json=payload,
        headers={"Authorization": f"Bearer {clinician_auth_token}"}
    )
    assert resp.status_code in (409, 422), resp.text
    body = resp.json()
    error_text = str(body).lower()
    assert any(k in error_text for k in ("state", "closed", "discharged", "encounter"))

import requests

def test_create_procedure_code_at_minimum_length_boundary(
    base_url, clinician_auth_token, open_encounter_id
):
    min_code = "X"  # exactly 1 character – minimum boundary
    payload = {
        "resourceType": "Procedure",
        "status": "completed",
        "code": {
            "coding": [{
                "system": "http://snomed.info/sct",
                "code": min_code
            }]
        },
        "subject": {"reference": "Patient/test-patient-1"},
        "encounter": {"reference": f"Encounter/{open_encounter_id}"}
    }
    resp = requests.post(
        f"{base_url}/Procedure",
        json=payload,
        headers={"Authorization": f"Bearer {clinician_auth_token}"}
    )
    assert resp.status_code == 201, (
        f"Expected 201 for min-boundary code length, got {resp.status_code}: {resp.text}"
    )
    assert "id" in resp.json()
